1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it.todo("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same");
15	  it.todo("live cell with 4 neighbors dies (overpopulation) — center of full 3x3 dies");
16	  it.todo("dead cell with exactly 3 neighbors becomes alive (reproduction) — [(0,2),(1,2),(0,1)] produces (1,1)");
17	  it.todo("blinker oscillates vertical→horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
18	  it.todo("handles negative coordinates correctly — blinker at negative offset oscillates");
19	});
